module fsm_example(input clk, input rst_n, input ctrl, output reg [1:0] state);
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n) state <= 2'b00;
    else if (ctrl) state <= state + 1;
  end
endmodule

output reg [1:0] ctrl_out;
output ctrl_bit0, ctrl_bit1;
assign ctrl_bit0 = ctrl_out[0];
assign ctrl_bit1 = ctrl_out[1];

casez ({state, ctrl_in})
  4'b00--: next_state = 2'b00;
  4'b01-1: next_state = 2'b01;
  4'b1-11: next_state = 2'b10;
endcase
